const CHARSETS = {
  uppercase: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ',
  lowercase: 'abcdefghijklmnopqrstuvwxyz',
  numbers: '0123456789',
  symbols: '!@#$%^&*()_+-=[]{}|;:,.<>?'
};
const ADVANCED_PATTERNS = [
  'qwerty',
  'asdf',
  'zxcv',
  '1234',
  'abcd',
  'password',
  'admin',
  'letmein'
];


const hasBadPattern = (password) => {
  const lower = password.toLowerCase();

  if (
    ADVANCED_PATTERNS.some(pattern =>
      lower.includes(pattern)
    )
  ) {
    return true;
  }


  if (/(.)\1{3,}/.test(password)) {
    return true;
  }


  if (/0123|1234|2345|abcd|bcde/.test(lower)) {
    return true;
  }


  return false;
};

// Cryptographically secure unbiased random integer [0, max) using rejection sampling
const getSecureRandomInt = (max) => {
  if (max <= 0 || max > 4294967295) throw new Error('Invalid max for random generation');
  const maxValid = Math.floor(4294967296 / max) * max;
  const arr = new Uint32Array(1);

  while (true) {
    window.crypto.getRandomValues(arr);
    if (arr[0] < maxValid) {
      return arr[0] % max;
    }
  }
};

export const generatePassword = (options) => {
  const opts = { length: 16, uppercase: true, lowercase: true, numbers: true, symbols: true, excludeSimilar: false, excludeAmbiguous: false, customExclude: '', ...options };

  let pool = '';
  const requiredPools = [];

  const addPool = (chars) => {
    let filtered = chars;
    if (opts.excludeSimilar) filtered = filtered.replace(/[il1Lo0O]/g, '');
    if (opts.excludeAmbiguous) filtered = filtered.replace(/[{}[\]()\/\\'"\`,;:~]/g, '');
    if (opts.customExclude) {
      const regex = new RegExp(`[${opts.customExclude.replace(/[-[\]{}()*+?.,\\^$|#\s]/g, '\\$&')}]`, 'g');
      filtered = filtered.replace(regex, '');
    }
    if (filtered.length > 0) {
      pool += filtered;
      requiredPools.push(filtered);
    }
  };

  if (opts.uppercase) addPool(CHARSETS.uppercase);
  if (opts.lowercase) addPool(CHARSETS.lowercase);
  if (opts.numbers) addPool(CHARSETS.numbers);
  if (opts.symbols) addPool(CHARSETS.symbols);

  if (pool.length === 0) return '';

  let password = '';
  let isValid = false;
  let attempts = 0;

  // Generate until we hit at least one character from every requested required pool
  while (!isValid && attempts < 100) {
    password = '';
    for (let i = 0; i < opts.length; i++) {
      password += pool[getSecureRandomInt(pool.length)];
    }

    isValid = opts.requireEach
      ? requiredPools.every(reqPool =>
        Array.from(password).some(char => reqPool.includes(char))
      )
      : true;


    if (opts.noRepeat && /(.)\1/.test(password)) {
      isValid = false;
    }


    if (opts.avoidPatterns && hasBadPattern(password)) {
      isValid = false;
    }
    attempts++;
  }
  if (hasBadPattern(password)) {
    return generatePassword(opts);
  }

  return password;
};

export const generatePassphrase = (wordCount = 4, separator = '-', capitalize = false) => {
  let words = [];
  for (let i = 0; i < wordCount; i++) {
    let word = WORDLIST[getSecureRandomInt(WORDLIST.length)];
    if (capitalize) word = word.charAt(0).toUpperCase() + word.slice(1);
    words.push(word);
  }

  const sepMap = {
    'hyphen': '-', 'space': ' ', 'dot': '.', 'none': '', 'number': () => getSecureRandomInt(10).toString()
  };

  if (separator === 'number') {
    return words.reduce((acc, word, idx) => idx === 0 ? word : acc + getSecureRandomInt(10).toString() + word, '');
  }

  return words.join(sepMap[separator] ?? '-');
};

export const calculateEntropy = (password) => {
  if (!password) return 0;
  let poolSize = 0;
  if (/[a-z]/.test(password)) poolSize += 26;
  if (/[A-Z]/.test(password)) poolSize += 26;
  if (/[0-9]/.test(password)) poolSize += 10;
  if (/[^a-zA-Z0-9]/.test(password)) poolSize += 32;

  return poolSize === 0 ? 0 : Math.floor(password.length * Math.log2(poolSize));
};

export const calculateStrength = (password) => {
  const entropy = calculateEntropy(password);
  let score = 0;
  let label = 'Very Weak';
  let color = 'var(--danger)';

  if (entropy < 28) { score = 0; label = 'Very Weak'; }
  else if (entropy < 36) { score = 1; label = 'Weak'; color = 'var(--warning)'; }
  else if (entropy < 60) { score = 2; label = 'Fair'; color = 'var(--accent)'; }
  else if (entropy < 128) { score = 3; label = 'Strong'; color = 'var(--success)'; }
  else { score = 4; label = 'Very Strong'; color = '#059669'; /* darker green */ }

  const lowerPass = password.toLowerCase();
  const patterns = ADVANCED_PATTERNS;
  if (patterns.some(p => lowerPass.includes(p)) || /(.)\1{2,}/.test(password)) {
    score = Math.max(0, score - 1);
    if (score <= 1) { label = 'Weak'; color = 'var(--danger)'; }
    if (score === 2) { label = 'Fair'; color = 'var(--warning)'; }
  }

  return { score, label, entropy, color };
};

export const checkPasswordReuse = (password, decryptedItems) => {
  if (!password) return [];
  return decryptedItems.filter(item =>
    item.decryptedData?.password === password || item.decryptedData?.licenseKey === password || item.decryptedData?.apiKey === password
  );


};